-- ----------------------------
-- Table structure for external_company_search_event
-- ----------------------------
DROP TABLE IF EXISTS `external_company_search_event`;
CREATE TABLE `external_company_search_event` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `task_id` bigint NOT NULL,
  `seq_no` bigint NOT NULL,
  `event_type` varchar(64) NOT NULL,
  `message` varchar(500) NOT NULL DEFAULT '',
  `payload` longtext,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_external_company_search_event_task_seq` (`task_id`,`seq_no`),
  KEY `idx_external_company_search_event_task_created_at` (`task_id`,`created_at`),
  CONSTRAINT `external_company_search_event_ibfk_1` FOREIGN KEY (`task_id`) REFERENCES `external_company_search_task` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=133 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

