-- ----------------------------
-- Table structure for external_company_search_result
-- ----------------------------
DROP TABLE IF EXISTS `external_company_search_result`;
CREATE TABLE `external_company_search_result` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `task_id` bigint NOT NULL,
  `company_id` bigint NOT NULL,
  `platform` tinyint NOT NULL,
  `keyword` varchar(255) NOT NULL,
  `region_keyword` varchar(255) NOT NULL DEFAULT '',
  `page_no` int NOT NULL DEFAULT '0',
  `rank_no` int NOT NULL DEFAULT '0',
  `is_new_company` tinyint(1) NOT NULL DEFAULT '0',
  `result_payload` longtext,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_external_company_search_result_task_company` (`task_id`,`company_id`),
  KEY `idx_external_company_search_result_task_id` (`task_id`),
  KEY `idx_external_company_search_result_company_id` (`company_id`),
  KEY `idx_external_company_search_result_created_at` (`created_at`),
  CONSTRAINT `external_company_search_result_ibfk_1` FOREIGN KEY (`task_id`) REFERENCES `external_company_search_task` (`id`) ON DELETE CASCADE,
  CONSTRAINT `external_company_search_result_ibfk_2` FOREIGN KEY (`company_id`) REFERENCES `external_company` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=73 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

