-- ----------------------------
-- Table structure for resource_pool
-- ----------------------------
DROP TABLE IF EXISTS `resource_pool`;
CREATE TABLE `resource_pool` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL DEFAULT '',
  `phone` varchar(128) NOT NULL DEFAULT '',
  `address` varchar(1024) NOT NULL DEFAULT '',
  `province` varchar(64) NOT NULL DEFAULT '',
  `city` varchar(64) NOT NULL DEFAULT '',
  `area` varchar(64) NOT NULL DEFAULT '',
  `latitude` double NOT NULL DEFAULT '0',
  `longitude` double NOT NULL DEFAULT '0',
  `source` varchar(32) NOT NULL DEFAULT 'baidu',
  `source_uid` varchar(150) NOT NULL DEFAULT '',
  `search_keyword` varchar(255) NOT NULL DEFAULT '',
  `search_radius` int NOT NULL DEFAULT '0',
  `search_region` varchar(255) NOT NULL DEFAULT '',
  `query_address` varchar(1024) NOT NULL DEFAULT '',
  `center_latitude` double NOT NULL DEFAULT '0',
  `center_longitude` double NOT NULL DEFAULT '0',
  `created_by` bigint NOT NULL DEFAULT '0',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `converted` tinyint(1) NOT NULL DEFAULT '0',
  `converted_customer_id` bigint DEFAULT NULL,
  `converted_at` datetime DEFAULT NULL,
  `converted_by` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_resource_pool_source_uid` (`source`,`source_uid`),
  KEY `idx_resource_pool_name` (`name`(191)),
  KEY `idx_resource_pool_phone` (`phone`),
  KEY `idx_resource_pool_city` (`city`),
  KEY `idx_resource_pool_updated_at` (`updated_at`),
  KEY `idx_resource_pool_converted` (`converted`),
  KEY `idx_resource_pool_converted_customer_id` (`converted_customer_id`)
) ENGINE=InnoDB AUTO_INCREMENT=101 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

